import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import OpenIDConnect, { useOidc, useUser } from '@remix-run/openidconnect';
import axios from 'axios';

const openIdConfig = {
  issuer: 'https://your-oidc-issuer.com',
  client_id: 'your-client-id',
  redirect_uri: window.location.origin,
};

function App() {
  const { isLoading, isAuthenticated } = useOidc(openIdConfig);
  const user = useUser();

  const login = () => window.location.href = openIdConfig.issuer + '/authorize';

  React.useEffect(() => {
    if (isAuthenticated) {
      axios.get('/userinfo')
        .then(res => console.log('User Profile:', res.data))
        .catch(err => console.error(err));
    }
  }, [isAuthenticated]);

  return (
    <Router>
      <Switch>
        {isLoading ? (
          <div>Loading...</div>
        ) : (
          <>
            <Route path="/" exact>
              {isAuthenticated ? (
                // User is logged in, render your app content here
                <div>Logged In</div>
              ) : (
                // User is not logged in, provide a login button
                <button onClick={login}>Login</button>
              )}
            </Route>
          </>
        )}
      </Switch>
    </Router>
  );
}

export default OpenIDConnect(App);